sys_script.script:
// Import the notification utility
var notificationUtil = new InsuranceNotificationUtils();

// Send notifications for significant claim status changes
if (current.claim_status.changes() || current.isNewRecord()) {
    var newStatus = current.getValue('claim_status');
    var previousStatus = previous ? previous.getValue('claim_status') : '';

    // Send notification for major status changes
    if (['approved', 'rejected', 'paid', 'closed'].indexOf(newStatus) !== -1) {
        notificationUtil.sendClaimsNotification(current, newStatus);

        var claimNumber = current.getValue('claim_number');
        var message = 'Claim ' + claimNumber + ' status updated to: ' + newStatus;
        gs.addInfoMessage(message);
    }
}

// Send notification when claim amount changes significantly
if (current.claim_amount.changes()) {
    var oldAmount = parseFloat(previous.getValue('claim_amount') || 0);
    var newAmount = parseFloat(current.getValue('claim_amount') || 0);
    var percentChange = Math.abs((newAmount - oldAmount) / oldAmount) * 100;

    if (percentChange > 20) { // If change is more than 20%
        gs.addInfoMessage('Significant claim amount change detected for claim: ' + 
                        current.getValue('claim_number'));
    }
}
